const actions = {
  addCategory: (title) => {
    setCategories((prev) => [
      ...prev,
      { id: `cat_${Date.now()}`, title, items: [] },
    ]);
  },

  deleteCategory: (id) => {
    setCategories((prev) => prev.filter((c) => c.id !== id));
  },

  openAdd: (categoryId) => {
    setModalConfig({
      isOpen: true,
      type: "add-item",
      categoryId,
      item: null,
      titlePrefix: "Add",
      titleMain: "New Item",
      submitLabel: "Create",
      initialValue: "",
      inputLabel: "Enter name for the new item",
    });
  },

  openEdit: (categoryId, item) => {
    setModalConfig({
      isOpen: true,
      type: "edit",
      categoryId,
      item,
      titlePrefix: "Edit",
      titleMain: "Item Name",
      submitLabel: "Update",
      initialValue: item.name,
    });
  },

  deleteItem: (categoryId, itemId) => {
    updateItems(categoryId, (items) => items.filter((i) => i.id !== itemId));
  },

  closeModal: () => setModalConfig({ isOpen: false }),

  handleModalSubmit: (newValue) => {
    const { type, categoryId, item } = modalConfig;

    if (type === "add-item") {
      updateItems(categoryId, (items) => [
        ...items,
        { id: Date.now(), name: newValue },
      ]);
    } else if (type === "edit") {
      updateItems(categoryId, (items) =>
        items.map((i) => (i.id === item.id ? { ...i, name: newValue } : i)),
      );
    }
    setModalConfig({ isOpen: false });
  },
};
